import psutil, subprocess, signal, time
from typing import Optional

# PIDs below this threshold belong to the OS — never kill them
SAFE_PID_MIN = 100

# Track background processes started by the agent this session
_agent_processes: dict[int, subprocess.Popen] = {}

def list_processes(name_filter: Optional[str] = None) -> list[dict]:
    """Return running processes, optionally filtered by name substring."""
    result = []
    for proc in psutil.process_iter(["pid", "name", "status", "cpu_percent", "memory_info"]):
        try:
            info = proc.info
            if name_filter and name_filter.lower() not in info["name"].lower():
                continue
            result.append({
                "pid": info["pid"],
                "name": info["name"],
                "status": info["status"],
                "cpu_percent": info["cpu_percent"],
                "memory_mb": round(info["memory_info"].rss / 1024 / 1024, 1) if info["memory_info"] else None,
            })
        except (psutil.NoSuchProcess, psutil.AccessDenied):
            pass
    return result[:50]  # cap to avoid flooding the context

def start_background(command: str, cwd: Optional[str] = None) -> dict:
    """Start a command in the background and return its PID.

    The process is tracked so it can be waited on or killed later.
    Uses list-form subprocess — no shell=True.
    """
    import shlex
    tokens = shlex.split(command)
    proc = subprocess.Popen(
        tokens, cwd=cwd,
        stdout=subprocess.DEVNULL,
        stderr=subprocess.DEVNULL,
    )
    _agent_processes[proc.pid] = proc
    return {"pid": proc.pid, "command": command, "status": "running"}

def kill_process(pid: int, force: bool = False) -> dict:
    """Send SIGTERM (or SIGKILL if force=True) to a process.

    Refuses to kill system PIDs and processes not started by this agent.
    """
    if pid < SAFE_PID_MIN:
        raise ValueError(f"Refusing to kill system PID {pid}")
    # Only allow killing processes the agent itself started
    if pid not in _agent_processes:
        raise ValueError(
            f"PID {pid} was not started by this agent. "
            "Use list_processes to inspect it, but only kill your own processes."
        )
    sig = signal.SIGKILL if force else signal.SIGTERM
    try:
        psutil.Process(pid).send_signal(sig)
    except psutil.NoSuchProcess:
        return {"pid": pid, "status": "already_gone"}
    return {"pid": pid, "signal": sig.name, "status": "signalled"}

def wait_for_process(pid: int, timeout: float = 30.0) -> dict:
    """Wait for a background process to finish and return its exit code."""
    if pid not in _agent_processes:
        raise ValueError(f"PID {pid} not tracked by this agent.")
    proc = _agent_processes[pid]
    try:
        proc.wait(timeout=timeout)
    except subprocess.TimeoutExpired:
        return {"pid": pid, "status": "still_running", "exit_code": None}
    return {"pid": pid, "status": "exited", "exit_code": proc.returncode}

import os, shutil, re, socket
from typing import Optional

SECRET_PATTERNS = re.compile(
    r"(SECRET|TOKEN|PASSWORD|PASSWD|API_KEY|PRIVATE|CREDENTIAL|AUTH)",
    re.IGNORECASE,
)

def get_env(key: str) -> dict:
    """Get a single environment variable by name, redacting secrets."""
    if SECRET_PATTERNS.search(key):
        return {"key": key, "value": "[REDACTED — secret variable]"}
    value = os.environ.get(key)
    return {"key": key, "value": value, "set": value is not None}

def list_env(prefix: Optional[str] = None) -> dict:
    """List environment variables (non-secret) matching an optional prefix."""
    result = {}
    for k, v in sorted(os.environ.items()):
        if prefix and not k.startswith(prefix.upper()):
            continue
        if SECRET_PATTERNS.search(k):
            result[k] = "[REDACTED]"
        else:
            result[k] = v
    return {"variables": result, "count": len(result)}

def which_binary(name: str) -> dict:
    """Find the full path of a binary on PATH."""
    path = shutil.which(name)
    return {"name": name, "path": path, "found": path is not None}

def check_port(host: str = "127.0.0.1", port: int = 8080) -> dict:
    """Check whether a TCP port is accepting connections."""
    # Block probing private/loopback ranges from external hosts
    # (here we allow localhost for dev server checks)
    with socket.socket(socket.AF_INET, socket.SOCK_STREAM) as s:
        s.settimeout(2)
        try:
            s.connect((host, port))
            return {"host": host, "port": port, "open": True}
        except (ConnectionRefusedError, socket.timeout, OSError):
            return {"host": host, "port": port, "open": False}

import psutil, platform, sys

def get_system_info() -> dict:
    """Return a snapshot of current system resource usage."""
    mem = psutil.virtual_memory()
    disk = psutil.disk_usage("/")
    cpu_count = psutil.cpu_count(logical=True)
    return {
        "platform": {
            "system": platform.system(),   # "Linux", "Darwin", "Windows"
            "release": platform.release(),
            "python": sys.version.split()[0],
        },
        "cpu": {
            "count_logical": cpu_count,
            "percent_used": psutil.cpu_percent(interval=0.5),
        },
        "memory": {
            "total_gb": round(mem.total / 1e9, 2),
            "available_gb": round(mem.available / 1e9, 2),
            "percent_used": mem.percent,
        },
        "disk": {
            "total_gb": round(disk.total / 1e9, 2),
            "free_gb": round(disk.free / 1e9, 2),
            "percent_used": disk.percent,
        },
    }

